// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---------------------------------------------------------

/**
 * Encode a compound cursor (created_at, id) into an opaque base64 string.
 */
function encodeCursor(row) {
    const payload = {
        // Use ISO string so the timestamp survives JSON round-tripping.
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque base64 cursor back into { created_at, id }.
 * Throws on anything malformed so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Invalid cursor: not valid base64-encoded JSON');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        !('created_at' in decoded) ||
        !('id' in decoded) ||
        Number.isNaN(Date.parse(decoded.created_at)) ||
        !Number.isInteger(decoded.id)
    ) {
        throw new Error('Invalid cursor: missing or malformed fields');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

// --- Handler ----------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    const { after } = req.query;

    // Build the query. We sort by (created_at DESC, id DESC), so the cursor
    // condition selects rows that come *after* the cursor in that ordering:
    //   created_at < cursor.created_at
    //   OR (created_at = cursor.created_at AND id < cursor.id)
    // This is expressed compactly with row-value comparison.
    let sql;
    let params;

    if (after !== undefined) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: err.message });
        }

        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        // Fetch limit + 1 (the N+1 trick) to detect whether more pages exist.
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // If we got limit + 1 rows, there's at least one more page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    // The next cursor points at the last row we're actually returning.
    const nextCursor =
        hasMore && posts.length > 0
            ? encodeCursor(posts[posts.length - 1])
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

### A note on the `(created_at, id) < ($1, $2)` row-value comparison

PostgreSQL supports comparing tuples directly, and it compares them lexicographically — exactly the semantics we want for a compound cursor. It is equivalent to, but cleaner than:

```sql
WHERE created_at < $1 OR (created_at = $1 AND id < $2)
```

Both work. The row-value form has a bonus: if you create a composite index `(created_at DESC, id DESC)` with matching column order, Postgres can use it efficiently as an index range scan.

```sql
CREATE INDEX idx_posts_pagination
  ON posts (created_at DESC, id DESC)
  WHERE published = true;
```

### Why cursor-based pagination is superior here

1. **Stable performance at scale.** `OFFSET N` forces Postgres to scan and discard the first `N` rows on every request. Page 10,000 means reading ~200,000 rows just to throw them away. A cursor uses a `WHERE` clause backed by an index, so fetching any page costs roughly the same — O(log n) seek + read of `limit` rows — regardless of how deep you are.

2. **No skipped or duplicated rows on a moving dataset.** With offset pagination, if a new post is inserted (or one deleted) between requests, every subsequent page shifts: a row can appear twice or get silently skipped. The cursor anchors to a concrete `(created_at, id)` position, so inserts/deletes elsewhere don't disturb the user's pagination.

3. **Drops the expensive `COUNT(*)`.** A full count on a large table is a costly scan and was only needed to compute `totalPages` for offset math. Cursor pagination doesn't need it — `hasMore` is derived almost for free via the N+1 trick.

The tradeoff: you lose random access to an arbitrary page ("jump to page 500") and a precise total count. For an infinite-scroll / "load more" feed sorted by recency, that's exactly the right tradeoff.

