// ─── Cursor helpers ────────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * `createdAt` is expected to be a Date object or ISO-8601 string (as returned
 * by node-postgres).
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload).toString('base64url'); // URL-safe base64
}

/**
 * Decodes a cursor string back to { createdAt, id }.
 * Returns null if the cursor is missing, not valid base64, not valid JSON,
 * or is missing required fields — all of which the caller should treat as a
 * 400 Bad Request.
 */
function decodeCursor(cursor) {
    if (!cursor) return null;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        if (!parsed.created_at || parsed.id == null) {
            return null; // structurally invalid
        }

        return {
            createdAt: parsed.created_at, // ISO-8601 string; PostgreSQL accepts this
            id: parsed.id,
        };
    } catch {
        return null; // base64 decode failed or JSON.parse threw
    }
}

// ─── Endpoint ──────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Parse and clamp limit. Capping prevents clients from requesting huge pages.
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after ?? null;

    // Decode cursor when provided; reject malformed values early.
    let cursor = null;
    if (afterParam !== null) {
        cursor = decodeCursor(afterParam);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed.',
            });
        }
    }

    // ── Build query ─────────────────────────────────────────────────────────────
    //
    // Fetch limit + 1 rows. If we get that extra row back, there IS a next page
    // (hasMore = true). We never return that extra row to the client.
    //
    // The WHERE predicate for the cursor implements the compound (created_at, id)
    // comparison that matches the ORDER BY created_at DESC, id DESC sort order:
    //
    //   "give me rows that sort strictly after the cursor position"
    //   ≡  created_at < cursor.created_at
    //      OR (created_at = cursor.created_at AND id < cursor.id)
    //
    // Written out explicitly (rather than as a row-value expression) so that
    // PostgreSQL can satisfy the condition with a standard composite index on
    // (created_at DESC, id DESC).

    let result;

    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                      created_at < $1
                      OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.createdAt, cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── Apply the N+1 trick ─────────────────────────────────────────────────────
    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows; // drop the sentinel row

    // Build the next cursor from the LAST row we actually return (not the sentinel).
    const nextCursor =
        hasMore
            ? encodeCursor(posts[posts.length - 1].created_at, posts[posts.length - 1].id)
            : null;

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null when this is the last page
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Problem with offset pagination | How cursors fix it |
|---|---|
| **`OFFSET N` is O(N)** — PostgreSQL must read and discard every preceding row before returning your page. Page 500 of 20 rows reads 10,000 rows and throws away 9,980. | The `WHERE (created_at, id) < (...)` predicate is a direct index seek — O(log N) regardless of how deep into the table you are. |
| **The expensive `COUNT(*)` query** — a full sequential scan on `posts` just to compute a page count that most users never need. | Eliminated entirely. The N+1 trick detects "is there a next page?" with zero extra queries. |
| **Rows shift under concurrent writes** — if a new post is published while a user is paginating, every subsequent `OFFSET` shifts by one, causing rows to be silently skipped or duplicated across pages. | Cursors are positional: "give me everything strictly after this row." New posts never disturb pages the client has already fetched. |
| **Deep pages get progressively slower** — a table with 10 M rows and `OFFSET 9_999_980` is genuinely painful. | Query time stays flat as the table grows, because the index entry for the cursor position is found directly. |

The one real trade-off: clients lose the ability to jump to an arbitrary page number (e.g. "go to page 47"). For an infinite-scroll feed or a "load more" button — which is the dominant pattern for `/api/posts` — that's never needed, making cursor pagination the right default.

